import{_ as p,c as e,o as s,ag as n}from"./chunks/framework.ELrfyV9R.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/2026-03-03-claude code.md","filePath":"ai/2026-03/2026-03-03-claude code.md","lastUpdated":1775818659000}'),t={name:"ai/2026-03/2026-03-03-claude code.md"};function l(i,a,o,d,c,r){return s(),e("div",null,a[0]||(a[0]=[n(`<h2 id="全局配置文件" tabindex="-1">全局配置文件 <a class="header-anchor" href="#全局配置文件" aria-label="Permalink to &quot;全局配置文件&quot;">​</a></h2><p>C:\\Users\\Administrator.claude</p><p>下面就从Claude Code 安装后好以后开始吧。</p><h2 id="的作用" tabindex="-1">?的作用 <a class="header-anchor" href="#的作用" aria-label="Permalink to &quot;?的作用&quot;">​</a></h2><h2 id="默认几种agent的切换" tabindex="-1">默认几种agent的切换 <a class="header-anchor" href="#默认几种agent的切换" aria-label="Permalink to &quot;默认几种agent的切换&quot;">​</a></h2><p>Alt+M</p><p>claude --dangerously-skip-permissions</p><ul><li>截图复制粘贴</li></ul><p>先把图片复制到剪贴板：截图：按 Win + Shift + S 或者Ctrl + C（截图工具） → 选区域 → 自动进剪贴板 或从任意地方复制图片（右键图片 → 复制图片）</p><p>在 Claude Code 的输入框（终端提示符处）按： Alt + V 或者Ctrl +V</p><p>拖拽也可以试试</p><p>/resume会话中断后一键续接，不用重新解释背景，省时省力 /compact上下文快满时压缩摘要，轻装继续，不让 Claude 遗忘关键信息 /clear任务切换时彻底清空，避免旧上下文污染新任务的判断</p><p>这个教程在过年期间就看到了，但是当时在家过年不方便去实践。</p><p>主要是针对手里有多个ChatGPT账号的人，当然大家也知道最近两个月ChatGPT 可以统一网页授权登录接管，智能轮询，对外提供魔法，对于小龙虾们的token暂时又有救了。</p><p>按照教程去安装是没问题的，直接docker安装省事方便，或者直接本地npm run运行也还凑合，但是对于非程序员来说，难度就有点大了。</p><p>所以这里我对这个工具进行了简单的修改升级为安装包，然后「一键安装」即可使用，类似CC Switch或者Antigravity Tools，可能很多人都使用过，就是跟他们类似的一个客户端，使用简单下载安装，然后右上角添加账号登录，下面复制API配置即可使用了，简直不要太简单。</p><p>作者八老板是个即将毕业的大学生，有可能是未来中国AI领域一颗闪耀的新星，毕竟能开发出这么一个工具来，还是非常厉害的，后续我也会继续关注他的动态。</p><p>不知道后期作者会不会提供此种方法。有需要的话，我会在评论区提供github上去下载安装即可。</p><p>相当于docker登录之后，就用您说的这个工具登录再输入url进去就完成配置了对吧？听起来是挺方便的。</p><p>另外，我最近几天用八总的这个github项目，有几个困惑，想找你们懂行的请教一下😍</p><p>一是做成了app类型的话，实则跟用Cli的体验差不多吧？🤔这一块我不太清楚😔</p><p>二是codex-proxy好像是把codex的推理能力固定在了中等推理强度吗？现在还可以调节推理强度吗？</p><p>😃😃希望大家能帮我解决困惑，非常感谢♥</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 如果文件不存在，先创建</span></span>
<span class="line"><span>touch ~/.bash_profile</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 用 vim 编辑</span></span>
<span class="line"><span>vim ~/.bash_profile</span></span></code></pre></div><p>进入文件</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 新增这一行, cc就是这个长命令的别名</span></span>
<span class="line"><span>alias cc=&#39;claude --dangerously-skip-permissions&#39;</span></span></code></pre></div><p>nano 是 Ctrl+O → Enter → Ctrl+X</p><p>// 执行这个命令使修改生效 source ~/.bashrc</p><p>// 看看是否存在自己命名的段命令 alias</p><p>让 Codex CLI 跳过人工批准（approvals）和沙箱限制（sandbox），以更自动化、权限更高的方式执行操作。GitHub 上相关讨论和 issue 里把它描述为“fully automated command”，并明确提示这是高风险模式。</p><p>alias cx=&#39;codex --dangerously-bypass-approvals-and-sandbox&#39;</p>`,31)]))}const m=p(t,[["render",l]]);export{h as __pageData,m as default};
